import{_ as e,o as i,c as t,aA as r}from"./chunks/framework.DyaeLj5o.js";const p=JSON.parse('{"title":"Why Julia for Eye-Tracking?","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/why-julia.md","filePath":"tutorials/why-julia.md","lastUpdated":null}'),o={name:"tutorials/why-julia.md"};function l(n,a,s,c,u,d){return i(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="Why-Julia-for-Eye-Tracking?" tabindex="-1">Why Julia for Eye-Tracking? <a class="header-anchor" href="#Why-Julia-for-Eye-Tracking?" aria-label="Permalink to &quot;Why Julia for Eye-Tracking? {#Why-Julia-for-Eye-Tracking?}&quot;">​</a></h1><p>Julia offers unique advantages for eye-tracking research:</p><h2 id="Speed-Without-Sacrifice" tabindex="-1">Speed Without Sacrifice <a class="header-anchor" href="#Speed-Without-Sacrifice" aria-label="Permalink to &quot;Speed Without Sacrifice {#Speed-Without-Sacrifice}&quot;">​</a></h2><p>Julia&#39;s just-in-time (JIT) compilation means EyeFun.jl&#39;s pure-Julia EDF binary reader is fast enough to replace C-based tools like <code>edf2asc</code>, while remaining easy to read, modify, and extend.</p><h2 id="Reproducibility" tabindex="-1">Reproducibility <a class="header-anchor" href="#Reproducibility" aria-label="Permalink to &quot;Reproducibility {#Reproducibility}&quot;">​</a></h2><p>Julia&#39;s package manager ensures exact reproducibility of analysis environments. Every dependency version is locked in <code>Manifest.toml</code>.</p><h2 id="DataFrames-Integration" tabindex="-1">DataFrames Integration <a class="header-anchor" href="#DataFrames-Integration" aria-label="Permalink to &quot;DataFrames Integration {#DataFrames-Integration}&quot;">​</a></h2><p>EyeFun.jl outputs standard <code>DataFrames.jl</code> tables, which integrate naturally with the entire Julia data science ecosystem — filtering, grouping, joining, and statistical analysis all use the same tools.</p><h2 id="Publication-Quality-Plots" tabindex="-1">Publication-Quality Plots <a class="header-anchor" href="#Publication-Quality-Plots" aria-label="Permalink to &quot;Publication-Quality Plots {#Publication-Quality-Plots}&quot;">​</a></h2><p><code>Makie.jl</code> provides interactive, customisable, publication-quality figures including gaze plots, heatmaps, scanpaths, and topographic maps.</p>',10)])])}const y=e(o,[["render",l]]);export{p as __pageData,y as default};
